<?php\n\nnamespace App\\Services\\Database;\n\nuse Illuminate\\Support\\Facades\\DB;\nuse Illuminate\\Support\\Facades\\Log;\nuse Illuminate\\Support\\Facades\\Schema;\n\nclass DatabaseOptimizer\n{\n    /**\n     * تنظيف سجلات التدقيق القديمة بناءً على التاريخ.\n     * \n     * @param int $days\n     * @return int\n     */\n    public function pruneAuditLogs(int $days = 30): int\n    {\n        $threshold = now()->subDays($days);\n\n        try {\n            $deleted = DB::table('audit_logs')\n                ->where('created_at', '<', $threshold)\n                ->delete();\n\n            Log::info("تم تنظيف سجلات التدقيق بنجاح. عدد السجلات المحذوفة: {$deleted}");\n            return $deleted;\n        } catch (\\Exception $e) {\n            Log::error("فشل في تنظيف سجلات التدقيق: " . $e->getMessage());\n            return 0;\n        }\n    }\n\n    /**\n     * تحسين أداء الجداول عبر إعادة بناء الفهارس (حسب نوع قاعدة البيانات).\n     * \n     * @return bool\n     */\n    public function optimizeTables(): bool\n    {\n        try {\n            $driver = config('database.default');\n            \n            if ($driver === 'mysql') {\n                $tables = DB::select('SHOW TABLES');\n                foreach ($tables as $table) {\n                    $tableName = reset($table);\n                    DB::statement("OPTIMIZE TABLE {$tableName}");\n                }\n            }\n\n            Log::info("تم تحسين فهارس الجداول بنجاح.");\n            return true;\n        } catch (\\Exception $e) {\n            Log::error("فشل في تحسين جداول قاعدة البيانات: " . $e->getMessage());\n            return false;\n        }\n    }\n\n    /**\n     * تنفيذ عملية صيانة شاملة.\n     * \n     * @return array\n     */\n    public function runFullMaintenance(): array\n    {\n        return [\n            'pruned_logs' => $this->pruneAuditLogs(),\n            'optimized_tables' => $this->optimizeTables()\n        ];\n    }\n}